import React from 'react';
import logoWhite from '../assets/logo-white.png';

const NAV = [
  { id: 'dashboard',     icon: '⊞', label: 'Dashboard'    },
  { id: 'miembros',      icon: '✦', label: 'Miembros'     },
  { id: 'cobradores',    icon: '◈', label: 'Cobradores'   },
  { id: 'cobranzas',     icon: '◎', label: 'Cobranzas'    },
  { id: 'reportes',      icon: '▦', label: 'Reportes'     },
  { id: 'configuracion', icon: '◧', label: 'Configuración'},
];

export default function Sidebar({ tab, setTab }) {
  return (
    <aside style={{
      width: 240,
      minHeight: '100vh',
      background: 'var(--navy)',
      display: 'flex',
      flexDirection: 'column',
      flexShrink: 0,
    }}>
      {/* Logo */}
      <div style={{
        padding: '32px 24px 28px',
        borderBottom: '1px solid rgba(255,255,255,0.08)',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'flex-start',
        gap: 12,
      }}>
        <img
          src={logoWhite}
          alt="Unión Pentecostal"
          style={{ width: 48, height: 48, objectFit: 'contain' }}
        />
        <div>
          <div style={{
            fontFamily: 'Georgia, serif',
            fontSize: 13,
            fontWeight: 700,
            color: 'var(--gold)',
            letterSpacing: '0.08em',
            textTransform: 'uppercase',
          }}>
            Unión Pentecostal
          </div>
          <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.45)', marginTop: 2 }}>
            Gestión de socios
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ flex: 1, padding: '16px 12px' }}>
        {NAV.map(item => {
          const active = tab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setTab(item.id)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 10,
                width: '100%',
                padding: '10px 14px',
                marginBottom: 2,
                borderRadius: 8,
                border: 'none',
                background: active ? 'rgba(200,155,60,0.18)' : 'transparent',
                color: active ? 'var(--gold-light)' : 'rgba(255,255,255,0.62)',
                fontSize: 14,
                fontWeight: active ? 600 : 400,
                textAlign: 'left',
                transition: 'background 0.15s, color 0.15s',
                cursor: 'pointer',
              }}
              onMouseEnter={e => { if (!active) e.currentTarget.style.background = 'rgba(255,255,255,0.06)'; }}
              onMouseLeave={e => { if (!active) e.currentTarget.style.background = 'transparent'; }}
            >
              <span style={{
                width: 28,
                height: 28,
                borderRadius: 6,
                background: active ? 'var(--gold)' : 'rgba(255,255,255,0.10)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 13,
                color: active ? 'var(--navy)' : 'rgba(255,255,255,0.5)',
                flexShrink: 0,
              }}>
                {item.icon}
              </span>
              {item.label}
            </button>
          );
        })}
      </nav>

      {/* Footer */}
      <div style={{
        padding: '16px 24px',
        borderTop: '1px solid rgba(255,255,255,0.08)',
        fontSize: 11,
        color: 'rgba(255,255,255,0.25)',
        lineHeight: 1.5,
      }}>
        Iglesia Evangélica<br />Unión Pentecostal
      </div>
    </aside>
  );
}
